import React, { useState, useEffect } from 'react';

function AvatarPreview({ user, measurements, outfit, onBack }) {
  const [svgContent, setSvgContent] = useState('');
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchProfile();
  }, []);

  const fetchProfile = async () => {
    try {
      const response = await fetch(`http://localhost:3000/api/users/${user.id}/profile`);
      const data = await response.json();
      setProfile(data);
      generateAvatar(data, measurements);
    } catch (error) {
      console.error('Error fetching profile:', error);
      generateAvatar(null, measurements);
    } finally {
      setLoading(false);
    }
  };

  const getSkinTone = (tone) => {
    const tones = {
      'Fair': '#ffc9a5',
      'Light': '#f4a582',
      'Medium': '#d4956e',
      'Tan': '#c9915d',
      'Deep': '#8b5a3c',
    };
    return tones[tone] || '#f4a460';
  };

  const getHairColor = () => {
    return '#3d2817';
  };

  const generateAvatar = (profileData, meas) => {
    const chest = meas?.chest || 36;
    const scale = Math.max(0.8, Math.min(1.4, chest / 36));
    const skinColor = getSkinTone(profileData?.profile?.skinTone || 'Medium');
    const hairColor = getHairColor();
    const bodyType = profileData?.profile?.bodyType || 'Average';

    let bodyScale = 1;
    if (bodyType === 'Petite') bodyScale = 0.85;
    if (bodyType === 'Plus-size') bodyScale = 1.25;
    if (bodyType === 'Tall') bodyScale = 1.1;

    const headRadius = 40 * scale;
    const bodyX = 200;
    const bodyY = 150;
    const shoulderWidth = 70 * scale * bodyScale;
    const bustWidth = 65 * scale * bodyScale;
    const hipWidth = 75 * scale * bodyScale;

    const svg = `<svg width="100%" height="100%" viewBox="0 0 400 650" xmlns="http://www.w3.org/2000/svg">
      <defs>
        <linearGradient id="skinGrad" x1="0%" y1="0%" x2="100%" y2="0%">
          <stop offset="0%" style="stop-color:${skinColor};stop-opacity:0.95" />
          <stop offset="50%" style="stop-color:${skinColor};stop-opacity:1" />
          <stop offset="100%" style="stop-color:${adjustColor(skinColor, -20)};stop-opacity:0.9" />
        </linearGradient>
        <radialGradient id="headShade" cx="35%" cy="35%">
          <stop offset="0%" style="stop-color:#fff;stop-opacity:0.4" />
          <stop offset="70%" style="stop-color:#000;stop-opacity:0" />
          <stop offset="100%" style="stop-color:#000;stop-opacity:0.15" />
        </radialGradient>
      </defs>

      <!-- Background -->
      <rect width="400" height="650" fill="#f8f8f8"/>

      <!-- Shadow under feet -->
      <ellipse cx="200" cy="600" rx="70" ry="15" fill="#00000020"/>

      <!-- HAIR -->
      <path d="M ${bodyX - headRadius * 0.9} ${bodyY - headRadius * 0.7} Q ${bodyX - headRadius} ${bodyY - headRadius * 1.1} ${bodyX} ${bodyY - headRadius * 1.15} Q ${bodyX + headRadius} ${bodyY - headRadius * 1.1} ${bodyX + headRadius * 0.9} ${bodyY - headRadius * 0.7}" fill="${hairColor}"/>
      <ellipse cx="${bodyX}" cy="${bodyY - headRadius * 0.5}" rx="${headRadius * 0.95}" ry="${headRadius * 0.8}" fill="${hairColor}"/>

      <!-- HEAD -->
      <circle cx="${bodyX}" cy="${bodyY}" r="${headRadius}" fill="url(#skinGrad)"/>
      <circle cx="${bodyX}" cy="${bodyY}" r="${headRadius}" fill="url(#headShade)"/>

      <!-- EARS -->
      <ellipse cx="${bodyX - headRadius - 8}" cy="${bodyY}" rx="12" ry="20" fill="${skinColor}"/>
      <ellipse cx="${bodyX + headRadius + 8}" cy="${bodyY}" rx="12" ry="20" fill="${skinColor}"/>

      <!-- EYEBROWS -->
      <path d="M ${bodyX - 22} ${bodyY - 8} Q ${bodyX - 12} ${bodyY - 12} ${bodyX - 2} ${bodyY - 8}" stroke="#5a4a3a" stroke-width="2.5" fill="none" stroke-linecap="round"/>
      <path d="M ${bodyX + 2} ${bodyY - 8} Q ${bodyX + 12} ${bodyY - 12} ${bodyX + 22} ${bodyY - 8}" stroke="#5a4a3a" stroke-width="2.5" fill="none" stroke-linecap="round"/>

      <!-- EYES -->
      <ellipse cx="${bodyX - 16}" cy="${bodyY - 2}" rx="8" ry="11" fill="#fff"/>
      <ellipse cx="${bodyX + 16}" cy="${bodyY - 2}" rx="8" ry="11" fill="#fff"/>
      <circle cx="${bodyX - 16}" cy="${bodyY}" r="6" fill="#6b4423"/>
      <circle cx="${bodyX + 16}" cy="${bodyY}" r="6" fill="#6b4423"/>
      <circle cx="${bodyX - 15}" cy="${bodyY - 2}" r="2.5" fill="#000"/>
      <circle cx="${bodyX + 17}" cy="${bodyY - 2}" r="2.5" fill="#000"/>
      <circle cx="${bodyX - 14.5}" cy="${bodyY - 3}" r="1.2" fill="#fff"/>
      <circle cx="${bodyX + 17.5}" cy="${bodyY - 3}" r="1.2" fill="#fff"/>

      <!-- NOSE -->
      <path d="M ${bodyX} ${bodyY + 2} L ${bodyX - 3} ${bodyY + 12} L ${bodyX + 3} ${bodyY + 12}" fill="${adjustColor(skinColor, -15)}" opacity="0.7"/>
      <circle cx="${bodyX - 4}" cy="${bodyY + 13}" r="2" fill="${adjustColor(skinColor, -20)}" opacity="0.5"/>
      <circle cx="${bodyX + 4}" cy="${bodyY + 13}" r="2" fill="${adjustColor(skinColor, -20)}" opacity="0.5"/>

      <!-- LIPS -->
      <path d="M ${bodyX - 12} ${bodyY + 20} Q ${bodyX} ${bodyY + 26} ${bodyX + 12} ${bodyY + 20}" fill="#d4746d" opacity="0.8"/>
      <path d="M ${bodyX - 12} ${bodyY + 20} Q ${bodyX} ${bodyY + 23} ${bodyX + 12} ${bodyY + 20}" fill="#e8a5a0" opacity="0.6"/>

      <!-- NECK -->
      <rect x="${bodyX - 18}" y="${bodyY + headRadius - 5}" width="36" height="20" fill="${skinColor}"/>
      <rect x="${bodyX - 18}" y="${bodyY + headRadius - 5}" width="36" height="20" fill="url(#skinGrad)"/>

      <!-- TORSO (with curves) -->
      <path d="M ${bodyX - shoulderWidth/2} ${bodyY + headRadius + 15} L ${bodyX - bustWidth/2} ${bodyY + headRadius + 70} L ${bodyX - hipWidth/2} ${bodyY + headRadius + 180} L ${bodyX + hipWidth/2} ${bodyY + headRadius + 180} L ${bodyX + bustWidth/2} ${bodyY + headRadius + 70} L ${bodyX + shoulderWidth/2} ${bodyY + headRadius + 15} Z" fill="${skinColor}"/>
      <path d="M ${bodyX - shoulderWidth/2} ${bodyY + headRadius + 15} L ${bodyX - bustWidth/2} ${bodyY + headRadius + 70} L ${bodyX - hipWidth/2} ${bodyY + headRadius + 180} L ${bodyX + hipWidth/2} ${bodyY + headRadius + 180} L ${bodyX + bustWidth/2} ${bodyY + headRadius + 70} L ${bodyX + shoulderWidth/2} ${bodyY + headRadius + 15} Z" fill="url(#skinGrad)"/>

      <!-- SHIRT -->
      <path d="M ${bodyX - bustWidth/2 - 5} ${bodyY + headRadius + 65} L ${bodyX - hipWidth/2} ${bodyY + headRadius + 180} L ${bodyX + hipWidth/2} ${bodyY + headRadius + 180} L ${bodyX + bustWidth/2 + 5} ${bodyY + headRadius + 65}" fill="#8B4789" stroke="#6B2F69" stroke-width="1.5"/>
      <!-- Shirt highlight -->
      <ellipse cx="${bodyX - 20}" cy="${bodyY + headRadius + 100}" rx="25" ry="40" fill="#fff" opacity="0.15"/>

      <!-- ARMS -->
      <ellipse cx="${bodyX - shoulderWidth/2 - 35}" cy="${bodyY + headRadius + 60}" rx="18" ry="50" fill="${skinColor}" transform="rotate(-20 ${bodyX - shoulderWidth/2 - 35} ${bodyY + headRadius + 60})"/>
      <ellipse cx="${bodyX + shoulderWidth/2 + 35}" cy="${bodyY + headRadius + 60}" rx="18" ry="50" fill="${skinColor}" transform="rotate(20 ${bodyX + shoulderWidth/2 + 35} ${bodyY + headRadius + 60})"/>

      <!-- HANDS -->
      <circle cx="${bodyX - shoulderWidth/2 - 50}" cy="${bodyY + headRadius + 140}" r="14" fill="${skinColor}"/>
      <circle cx="${bodyX + shoulderWidth/2 + 50}" cy="${bodyY + headRadius + 140}" r="14" fill="${skinColor}"/>

      <!-- PANTS -->
      <path d="M ${bodyX - hipWidth/2} ${bodyY + headRadius + 180} L ${bodyX - hipWidth/2 + 10} ${bodyY + headRadius + 340} L ${bodyX - 5} ${bodyY + headRadius + 340} L ${bodyX - hipWidth/2} ${bodyY + headRadius + 180}" fill="#1a1a1a"/>
      <path d="M ${bodyX + hipWidth/2} ${bodyY + headRadius + 180} L ${bodyX + hipWidth/2 - 10} ${bodyY + headRadius + 340} L ${bodyX + 5} ${bodyY + headRadius + 340} L ${bodyX + hipWidth/2} ${bodyY + headRadius + 180}" fill="#0d0d0d"/>

      <!-- FEET -->
      <ellipse cx="${bodyX - 15}" cy="${bodyY + headRadius + 360}" rx="18" ry="12" fill="#1a1a1a"/>
      <ellipse cx="${bodyX + 15}" cy="${bodyY + headRadius + 360}" rx="18" ry="12" fill="#1a1a1a"/>

      <!-- Text labels -->
      <text x="200" y="590" text-anchor="middle" font-size="16" font-weight="bold" fill="#333">Your Virtual Avatar</text>
      <text x="200" y="615" text-anchor="middle" font-size="11" fill="#888">${bodyType} • ${profileData?.profile?.skinTone || 'Profile'}</text>
    </svg>`;

    setSvgContent(svg);
  };

  const adjustColor = (color, amount) => {
    const usePound = color[0] === "#";
    const col = usePound ? color.slice(1) : color;
    const num = parseInt(col, 16);
    const r = Math.max(0, Math.min(255, (num >> 16) + amount));
    const g = Math.max(0, Math.min(255, (num >> 8 & 0x00FF) + amount));
    const b = Math.max(0, Math.min(255, (num & 0x0000FF) + amount));
    return (usePound ? "#" : "") + (0x1000000 + r * 0x10000 + g * 0x100 + b).toString(16).slice(1);
  };

  if (loading) return <div className="App"><div className="card"><p>Loading avatar...</p></div></div>;

  return (
    <div className="App avatar-preview">
      <div className="navbar">
        <h1>👤 Your Avatar</h1>
        <button onClick={onBack} className="back-btn">← Back</button>
      </div>
      <div className="avatar-container">
        <div className="avatar-display" dangerouslySetInnerHTML={{ __html: svgContent }} />
        <div className="avatar-info">
          <h2>Your Profile</h2>
          {profile && (
            <div className="info-box">
              <p><strong>Body Type:</strong> {profile.profile?.bodyType || 'Not set'}</p>
              <p><strong>Skin Tone:</strong> {profile.profile?.skinTone || 'Not set'}</p>
              <p><strong>Style:</strong> {profile.profile?.style || 'Not set'}</p>
              <hr style={{margin: '15px 0', border: 'none', borderTop: '1px solid #ddd'}} />
              <p><strong>Chest:</strong> {profile.measurements?.chest || 'Not set'}"</p>
              <p><strong>Waist:</strong> {profile.measurements?.waist || 'Not set'}"</p>
              <p><strong>Hips:</strong> {profile.measurements?.hips || 'Not set'}"</p>
              <p><strong>Height:</strong> {profile.measurements?.height || 'Not set'}'</p>
            </div>
          )}
          <button onClick={onBack} className="btn-primary" style={{width: '100%', marginTop: '20px'}}>← Back to Dashboard</button>
        </div>
      </div>
    </div>
  );
}

export default AvatarPreview;
